export type StructuredDataFormat = 'jsonld' | 'microdata' | 'rdfa';

export type StructuredDataProvenance = 'declared' | 'derived' | 'speculative';

export interface StructuredDataSourceSpan {
  file: string;
  startLine: number;
  startColumn: number;
  endLine: number;
  endColumn: number;
}

export interface StructuredDataContextMap {
  [prefix: string]: string;
}

export interface StructuredDataDeclaration {
  sdType?: string;
  sdId?: string;
  sdProp?: string;
  sdRef?: string;
  sdValue?: string;
  sdLang?: string;
  sdContext?: StructuredDataContextMap;
  sdContextError?: string;
  textContent?: string;
  sourceSpan?: StructuredDataSourceSpan;
}

export type StructuredDataNodeRef =
  | { kind: 'iri'; iri: string }
  | { kind: 'blank'; id: string };

export interface StructuredDataLiteral {
  kind: 'literal';
  value: string;
  language?: string;
}

export interface StructuredDataTriple {
  subject: StructuredDataNodeRef;
  predicate: string;
  object: StructuredDataNodeRef | StructuredDataLiteral;
  provenance: StructuredDataProvenance;
  sourceSpan?: StructuredDataSourceSpan;
}

export interface StructuredDataGraph {
  routeId: string;
  context: StructuredDataContextMap;
  triples: StructuredDataTriple[];
  schemaTypes: string[];
  vocabularies: string[];
  tripleCount: number;
}

export interface StructuredDataGraphSummary {
  schemaTypes: string[];
  tripleCount: number;
  vocabularies: string[];
}

export type StructuredDataValidationCode =
  | 'SD_UNRESOLVED_REF'
  | 'SD_INCOMPATIBLE_DUPLICATE_ID'
  | 'SD_INVALID_CONTEXT_MAP'
  | 'SD_ILLEGAL_LITERAL_SHAPE'
  | 'SD_CONFLICTING_ROUTE_DECLARATIONS';

export interface StructuredDataValidationIssue {
  code: StructuredDataValidationCode;
  message: string;
  severity: 'warning' | 'error';
  sourceSpan?: StructuredDataSourceSpan;
}

export interface StructuredDataCompilationResult {
  graph: StructuredDataGraph;
  issues: StructuredDataValidationIssue[];
}

export interface StructuredDataRouteContext {
  routeId?: string;
  baseIri?: string;
  context?: StructuredDataContextMap;
  speculative?: boolean;
}

export interface StructuredDataEmitOptions {
  formats?: StructuredDataFormat[];
  compactContext?: boolean;
}

export interface StructuredDataEmitResult {
  jsonld?: string;
  rdfa?: string;
  microdata?: string;
  skippedMicrodataTriples: number;
}

export type StructuredProofSystem =
  | 'lean4'
  | 'aeon-logic'
  | 'tlaplus'
  | 'gg'
  | 'coq'
  | 'agda'
  | string;

export interface StructuredProofDeclaration {
  system: StructuredProofSystem;
  theorem: string;
  status?: 'verified' | 'sorry' | 'conjecture';
  source?: string;
  expression?: string;
  sourceSpan?: StructuredDataSourceSpan;
}

export interface StructuredProofAttrInput {
  theorem: string;
  system: StructuredProofSystem;
  status?: 'verified' | 'sorry' | 'conjecture';
  source?: string;
  expression?: string;
}

export interface StructuredDataCodemodPlan {
  pattern:
    | 'Organization'
    | 'PersonContactPoint'
    | 'FAQPage'
    | 'Recipe'
    | 'Product'
    | 'Event'
    | 'Article';
  declarations: StructuredDataDeclaration[];
}

const DEFAULT_CONTEXT: StructuredDataContextMap = {
  schema: 'https://schema.org/',
  rdf: 'http://www.w3.org/1999/02/22-rdf-syntax-ns#',
  rdfs: 'http://www.w3.org/2000/01/rdf-schema#',
  xsd: 'http://www.w3.org/2001/XMLSchema#',
  foaf: 'http://xmlns.com/foaf/0.1/',
};

const RDF_TYPE = 'http://www.w3.org/1999/02/22-rdf-syntax-ns#type';
const SCHEMA_BASE = 'https://schema.org/';

/**
 * Handles the gnosis extract Structured Declarations workflow.
 */
export function extractStructuredDeclarations(
  source: string,
  filePath: string
): StructuredDataDeclaration[] {
  const declarations: StructuredDataDeclaration[] = [];
  const tokenRegex = /<\/?[A-Za-z][^>]*>/g;
  const stack: StructuredDataContextMap[] = [Object.freeze({ ...DEFAULT_CONTEXT })];

  for (const match of source.matchAll(tokenRegex)) {
    const token = match[0];
    const index = match.index ?? 0;
    const isCloseTag = token.startsWith('</');
    const isSelfClosing = /\/>\s*$/.test(token);

    if (isCloseTag) {
      if (stack.length > 1) {
        stack.pop();
      }
      continue;
    }

    const attrs = parseAttributes(token);
    const topContext = stack[stack.length - 1] ?? DEFAULT_CONTEXT;

    const localContextRaw = attrs['data-sd-context'];
    let localContext: StructuredDataContextMap | undefined;
    let contextError: string | undefined;
    if (localContextRaw !== undefined) {
      const parsed = parseContextMap(localContextRaw);
      if ('error' in parsed) {
        contextError = parsed.error;
      } else {
        localContext = parsed.context;
      }
    }

    const effectiveContext: StructuredDataContextMap = {
      ...topContext,
      ...(localContext ?? {}),
    };

    const hasStructuredEntityAttr = Object.keys(attrs).some(
      (key) => key.startsWith('data-sd-') && key !== 'data-sd-context'
    );
    if (hasStructuredEntityAttr || contextError !== undefined) {
      declarations.push({
        ...(attrs['data-sd-type'] !== undefined && { sdType: attrs['data-sd-type'] }),
        ...(attrs['data-sd-id'] !== undefined && { sdId: attrs['data-sd-id'] }),
        ...(attrs['data-sd-prop'] !== undefined && { sdProp: attrs['data-sd-prop'] }),
        ...(attrs['data-sd-ref'] !== undefined && { sdRef: attrs['data-sd-ref'] }),
        ...(attrs['data-sd-value'] !== undefined && { sdValue: attrs['data-sd-value'] }),
        ...(attrs['data-sd-lang'] !== undefined && { sdLang: attrs['data-sd-lang'] }),
        sdContext: effectiveContext,
        ...(contextError !== undefined && { sdContextError: contextError }),
        sourceSpan: sourceIndexToSpan(source, index, filePath),
      });
    }

    if (!isSelfClosing) {
      stack.push(effectiveContext);
    }
  }

  return declarations.sort(compareDeclarationOrder);
}

/**
 * Parses the Proof Declaration From Attributes.
 */
export function parseProofDeclarationFromAttributes(
  attributes: Record<string, string>,
  sourceSpan?: StructuredDataSourceSpan
): StructuredProofDeclaration | null {
  const raw = attributes['data-proof'];
  if (!raw) {
    return null;
  }

  const parts = raw.split(':');
  if (parts.length < 2) {
    return null;
  }

  const system = parts.shift()?.trim();
  const theorem = parts.join(':').trim();
  if (!system || !theorem) {
    return null;
  }

  const status = attributes['data-proof-status'];
  const typedStatus =
    status === 'verified' || status === 'sorry' || status === 'conjecture'
      ? status
      : undefined;

  return {
    system,
    theorem,
    ...(typedStatus !== undefined && { status: typedStatus }),
    ...(attributes['data-proof-source'] !== undefined && { source: attributes['data-proof-source'] }),
    ...(attributes['data-proof-expr'] !== undefined && { expression: attributes['data-proof-expr'] }),
    ...(sourceSpan !== undefined && { sourceSpan }),
  };
}

/**
 * Parses the Proof Declaration From Value.
 */
export function parseProofDeclarationFromValue(
  rawProof: string,
  options?: {
    status?: 'verified' | 'sorry' | 'conjecture';
    source?: string;
    expression?: string;
    sourceSpan?: StructuredDataSourceSpan;
  }
): StructuredProofDeclaration | null {
  return parseProofDeclarationFromAttributes(
    {
      'data-proof': rawProof,
      ...(options?.status ? { 'data-proof-status': options.status } : {}),
      ...(options?.source ? { 'data-proof-source': options.source } : {}),
      ...(options?.expression ? { 'data-proof-expr': options.expression } : {}),
    },
    options?.sourceSpan
  );
}

/**
 * Handles the gnosis proof Attr workflow.
 */
export function proofAttr(input: StructuredProofAttrInput): string {
  const attrs: string[] = [
    `data-proof="${escapeAttr(`${input.system}:${input.theorem}`)}"`,
  ];
  if (input.status) {
    attrs.push(`data-proof-status="${escapeAttr(input.status)}"`);
  }
  if (input.source) {
    attrs.push(`data-proof-source="${escapeAttr(input.source)}"`);
  }
  if (input.expression) {
    attrs.push(`data-proof-expr="${escapeAttr(input.expression)}"`);
  }
  return attrs.join(' ');
}

/**
 * Handles the gnosis compile Structured Graph workflow.
 */
export function compileStructuredGraph(
  declarations: StructuredDataDeclaration[],
  routeContext: StructuredDataRouteContext = {}
): StructuredDataCompilationResult {
  const sortedDeclarations = [...declarations].sort(compareDeclarationOrder);
  const context: StructuredDataContextMap = {
    ...DEFAULT_CONTEXT,
    ...(routeContext.context ?? {}),
  };
  const issues: StructuredDataValidationIssue[] = [];
  const routeId = routeContext.routeId ?? '/';
  const triples: StructuredDataTriple[] = [];
  const knownNodeIds = new Set<string>();
  const pendingRefs: Array<{
    ref: string;
    tripleIndex: number;
    declaration: StructuredDataDeclaration;
  }> = [];
  const idLiteralFingerprint = new Map<string, string>();

  for (const declaration of sortedDeclarations) {
    if (declaration.sdContextError) {
      issues.push({
        code: 'SD_INVALID_CONTEXT_MAP',
        message: `Invalid data-sd-context JSON: ${declaration.sdContextError}`,
        severity: 'error',
        ...(declaration.sourceSpan !== undefined && { sourceSpan: declaration.sourceSpan }),
      });
    }

    const effectiveContext = {
      ...context,
      ...(declaration.sdContext ?? {}),
    };

    const subject = resolveSubject(declaration, routeContext, effectiveContext);
    if (subject.kind === 'iri') {
      knownNodeIds.add(subject.iri);
    } else {
      knownNodeIds.add(`_:${subject.id}`);
    }

    if (declaration.sdType) {
      const expandedType = expandIri(
        declaration.sdType,
        effectiveContext,
        routeContext.baseIri
      );
      triples.push({
        subject,
        predicate: RDF_TYPE,
        object: { kind: 'iri', iri: expandedType },
        provenance: 'declared',
        ...(declaration.sourceSpan !== undefined && { sourceSpan: declaration.sourceSpan }),
      });
    }

    if (declaration.sdProp) {
      const predicate = expandIri(
        declaration.sdProp,
        effectiveContext,
        routeContext.baseIri
      );

      if (declaration.sdRef) {
        const refIri = expandIri(
          declaration.sdRef,
          effectiveContext,
          routeContext.baseIri
        );
        const triple: StructuredDataTriple = {
          subject,
          predicate,
          object: { kind: 'iri', iri: refIri },
          provenance: 'declared',
          ...(declaration.sourceSpan !== undefined && { sourceSpan: declaration.sourceSpan }),
        };
        triples.push(triple);
        pendingRefs.push({
          ref: refIri,
          tripleIndex: triples.length - 1,
          declaration,
        });
      } else {
        const rawLiteral =
          declaration.sdValue ?? declaration.textContent ?? declaration.sdId;
        if (!rawLiteral || rawLiteral.trim().length === 0) {
          issues.push({
            code: 'SD_ILLEGAL_LITERAL_SHAPE',
            message: `Literal value is required for ${declaration.sdProp} when data-sd-ref is not provided.`,
            severity: 'error',
            ...(declaration.sourceSpan !== undefined && { sourceSpan: declaration.sourceSpan }),
          });
        } else {
          if (/^\s*[[{]/.test(rawLiteral.trim())) {
            issues.push({
              code: 'SD_ILLEGAL_LITERAL_SHAPE',
              message:
                'Literal appears to contain JSON object/array text. Use data-sd-ref or scalar literal values.',
              severity: 'warning',
              ...(declaration.sourceSpan !== undefined && { sourceSpan: declaration.sourceSpan }),
            });
          }
          const literalFingerprintKey = `${nodeKey(subject)}|${predicate}`;
          const prev = idLiteralFingerprint.get(literalFingerprintKey);
          if (prev && prev !== rawLiteral) {
            issues.push({
              code: 'SD_INCOMPATIBLE_DUPLICATE_ID',
              message:
                'Duplicate declaration assigns conflicting literal values to the same subject/predicate pair.',
              severity: 'error',
              ...(declaration.sourceSpan !== undefined && { sourceSpan: declaration.sourceSpan }),
            });
          }
          idLiteralFingerprint.set(literalFingerprintKey, rawLiteral);
          triples.push({
            subject,
            predicate,
            object: {
              kind: 'literal',
              value: rawLiteral,
              ...(declaration.sdLang !== undefined && { language: declaration.sdLang }),
            },
            provenance: 'declared',
            ...(declaration.sourceSpan !== undefined && { sourceSpan: declaration.sourceSpan }),
          });
        }
      }
    }
  }

  for (const pendingRef of pendingRefs) {
    if (!knownNodeIds.has(pendingRef.ref)) {
      issues.push({
        code: 'SD_UNRESOLVED_REF',
        message: `Reference '${pendingRef.ref}' does not resolve to a declared node ID in this route scope.`,
        severity: 'error',
        ...(pendingRef.declaration.sourceSpan !== undefined && { sourceSpan: pendingRef.declaration.sourceSpan }),
      });
      const triple = triples[pendingRef.tripleIndex];
      if (triple) {
        triple.provenance = 'derived';
      }
    }
  }

  if (routeContext.speculative) {
    const subjectsWithName = new Set<string>();
    for (const triple of triples) {
      if (
        triple.predicate === `${SCHEMA_BASE}name` &&
        triple.object.kind === 'literal'
      ) {
        subjectsWithName.add(nodeKey(triple.subject));
      }
    }

    for (const triple of triples) {
      if (triple.predicate !== RDF_TYPE || triple.object.kind !== 'iri') {
        continue;
      }
      const key = nodeKey(triple.subject);
      if (subjectsWithName.has(key)) {
        continue;
      }
      const speculativeName = deriveSpeculativeName(triple.object.iri);
      if (!speculativeName) {
        continue;
      }
      triples.push({
        subject: triple.subject,
        predicate: `${SCHEMA_BASE}name`,
        object: { kind: 'literal', value: speculativeName },
        provenance: 'speculative',
        ...(triple.sourceSpan !== undefined && { sourceSpan: triple.sourceSpan }),
      });
      subjectsWithName.add(key);
    }
  }

  const routeRootTypeSet = new Set<string>();
  for (const triple of triples) {
    if (triple.predicate === RDF_TYPE && triple.object.kind === 'iri') {
      routeRootTypeSet.add(triple.object.iri);
    }
  }
  if (routeRootTypeSet.size > 24) {
    issues.push({
      code: 'SD_CONFLICTING_ROUTE_DECLARATIONS',
      message:
        'Route declares an unusually large number of root types. Verify route-level declarations are not conflicting.',
      severity: 'warning',
    });
  }

  const schemaTypes = Array.from(
    new Set(
      triples
        .filter((triple) => triple.predicate === RDF_TYPE)
        .map((triple) =>
          triple.object.kind === 'iri' ? triple.object.iri : undefined
        )
        .filter((value): value is string => typeof value === 'string')
    )
  ).sort();

  const vocabularies = Array.from(
    new Set(
      triples
        .map((triple) => vocabularyOfIri(triple.predicate))
        .filter((value): value is string => value !== null)
    )
  ).sort();

  const graph: StructuredDataGraph = {
    routeId,
    context,
    triples,
    schemaTypes,
    vocabularies,
    tripleCount: triples.length,
  };

  return { graph, issues };
}

/**
 * Handles the gnosis emit Structured Data workflow.
 */
export function emitStructuredData(
  graph: StructuredDataGraph,
  options: StructuredDataEmitOptions = {}
): StructuredDataEmitResult {
  const formats = options.formats ?? ['jsonld'];
  let jsonld: string | undefined;
  let rdfa: string | undefined;
  let microdata: string | undefined;
  let skippedMicrodataTriples = 0;

  if (formats.includes('jsonld')) {
    const compact = options.compactContext !== false;
    const nodeMap = new Map<string, Record<string, unknown>>();
    for (const triple of graph.triples) {
      const subjectKey = nodeKey(triple.subject);
      const subjectNode = nodeMap.get(subjectKey) ?? { '@id': serializeNodeRef(triple.subject) };
      const predicate = compact
        ? compactIri(triple.predicate, graph.context)
        : triple.predicate;

      if (triple.predicate === RDF_TYPE && triple.object.kind === 'iri') {
        const typeValue = compact
          ? compactIri(triple.object.iri, graph.context)
          : triple.object.iri;
        pushJsonLdValue(subjectNode, '@type', typeValue);
      } else {
        const objectValue =
          triple.object.kind === 'literal'
            ? literalToJsonLd(triple.object)
            : { '@id': serializeNodeRef(triple.object) };
        pushJsonLdValue(subjectNode, predicate, objectValue);
      }

      nodeMap.set(subjectKey, subjectNode);
    }

    const graphObject: Record<string, unknown> = {
      ...(compact ? { '@context': graph.context } : {}),
      '@graph': Array.from(nodeMap.values()),
    };
    jsonld = JSON.stringify(graphObject, null, 2);
  }

  if (formats.includes('rdfa')) {
    const lines: string[] = ['<div vocab="https://schema.org/">'];
    const grouped = groupTriplesBySubject(graph.triples);
    for (const [subject, triples] of grouped.entries()) {
      lines.push(`  <div about="${escapeAttr(subject)}">`);
      for (const triple of triples) {
        if (triple.predicate === RDF_TYPE && triple.object.kind === 'iri') {
          lines.push(
            `    <span typeof="${escapeAttr(triple.object.iri)}"></span>`
          );
          continue;
        }

        if (triple.object.kind === 'literal') {
          lines.push(
            `    <meta property="${escapeAttr(triple.predicate)}" content="${escapeAttr(triple.object.value)}"${
              triple.object.language
                ? ` lang="${escapeAttr(triple.object.language)}"`
                : ''
            } />`
          );
        } else {
          lines.push(
            `    <link property="${escapeAttr(triple.predicate)}" href="${escapeAttr(serializeNodeRef(triple.object))}" />`
          );
        }
      }
      lines.push('  </div>');
    }
    lines.push('</div>');
    rdfa = lines.join('\n');
  }

  if (formats.includes('microdata')) {
    const lines: string[] = [];
    const grouped = groupTriplesBySubject(graph.triples);

    for (const [subject, triples] of grouped.entries()) {
      const typeTriple = triples.find(
        (triple) => triple.predicate === RDF_TYPE && triple.object.kind === 'iri'
      );
      if (!typeTriple || typeTriple.object.kind !== 'iri') {
        skippedMicrodataTriples += triples.length;
        continue;
      }
      const microType = toMicrodataType(typeTriple.object.iri);
      if (!microType) {
        skippedMicrodataTriples += triples.length;
        continue;
      }

      lines.push(
        `<div itemscope itemtype="${escapeAttr(microType)}" itemid="${escapeAttr(subject)}">`
      );
      for (const triple of triples) {
        if (triple.predicate === RDF_TYPE) {
          continue;
        }
        const itemprop = toMicrodataProp(triple.predicate);
        if (!itemprop) {
          skippedMicrodataTriples += 1;
          continue;
        }
        if (triple.object.kind === 'literal') {
          lines.push(
            `  <meta itemprop="${escapeAttr(itemprop)}" content="${escapeAttr(triple.object.value)}" />`
          );
        } else {
          lines.push(
            `  <link itemprop="${escapeAttr(itemprop)}" href="${escapeAttr(serializeNodeRef(triple.object))}" />`
          );
        }
      }
      lines.push('</div>');
    }

    microdata = lines.join('\n');
  }

  return {
    ...(jsonld !== undefined && { jsonld }),
    ...(rdfa !== undefined && { rdfa }),
    ...(microdata !== undefined && { microdata }),
    skippedMicrodataTriples,
  };
}

/**
 * Handles the gnosis summarize Structured Data Graph workflow.
 */
export function summarizeStructuredDataGraph(
  graph: StructuredDataGraph
): StructuredDataGraphSummary {
  return {
    schemaTypes: [...graph.schemaTypes],
    tripleCount: graph.tripleCount,
    vocabularies: [...graph.vocabularies],
  };
}

