/**
 * Handles the gnosis json Ld To Declarations workflow.
 */
export function jsonLdToDeclarations(
  input: Record<string, unknown> | Record<string, unknown>[]
): StructuredDataDeclaration[] {
  const declarations: StructuredDataDeclaration[] = [];
  const nodes = Array.isArray(input) ? input : [input];
  let autoNode = 0;

  const visitNode = (
    node: Record<string, unknown>,
    parentId?: string,
    parentPredicate?: string
  ): string => {
    const nodeIdRaw = valueToString(node['@id']) ?? `#jsonld-node-${autoNode++}`;
    const nodeId = nodeIdRaw.startsWith('#') ? nodeIdRaw : `#${nodeIdRaw}`;
    const contextValue = node['@context'];
    const context =
      contextValue && typeof contextValue === 'object' && !Array.isArray(contextValue)
        ? (contextValue as Record<string, string>)
        : undefined;
    const typeValue = node['@type'];
    const normalizedTypes = Array.isArray(typeValue)
      ? typeValue.map((value) => normalizeSemanticType(String(value)))
      : typeValue
        ? [normalizeSemanticType(String(typeValue))]
        : [];
    if (normalizedTypes.length > 0) {
      for (const sdType of normalizedTypes) {
        declarations.push({
          sdId: nodeId,
          sdType,
          ...(context ? { sdContext: context } : {}),
        });
      }
    } else {
      declarations.push({
        sdId: nodeId,
        sdType: 'schema:Thing',
        ...(context ? { sdContext: context } : {}),
      });
    }

    if (parentId && parentPredicate) {
      declarations.push({
        sdId: parentId,
        sdProp: normalizeSemanticType(parentPredicate),
        sdRef: nodeId,
      });
    }

    for (const [key, value] of Object.entries(node)) {
      if (key === '@context' || key === '@id' || key === '@type') {
        continue;
      }
      const predicate = normalizeSemanticType(key);
      const values = Array.isArray(value) ? value : [value];
      for (const item of values) {
        if (item === null || item === undefined) {
          continue;
        }
        if (typeof item === 'object') {
          const typedObject = item as Record<string, unknown>;
          if (typeof typedObject['@value'] === 'string') {
            declarations.push({
              sdId: nodeId,
              sdProp: predicate,
              sdValue: typedObject['@value'],
              ...(typeof typedObject['@language'] === 'string' && { sdLang: typedObject['@language'] }),
            });
          } else {
            visitNode(typedObject, nodeId, predicate);
          }
          continue;
        }
        declarations.push({
          sdId: nodeId,
          sdProp: predicate,
          sdValue: String(item),
        });
      }
    }

    return nodeId;
  };

  for (const node of nodes) {
    visitNode(node);
  }

  return declarations;
}

function valueToString(value: unknown): string | undefined {
  if (typeof value === 'string') {
    return value;
  }
  if (typeof value === 'number' || typeof value === 'boolean') {
    return String(value);
  }
  return undefined;
}

function normalizeSemanticType(value: string): string {
  const normalized = value.trim();
  if (!normalized) {
    return 'schema:Thing';
  }
  if (
    normalized.startsWith('http://') ||
    normalized.startsWith('https://') ||
    normalized.includes(':')
  ) {
    return normalized;
  }
  return `schema:${normalized}`;
}

function deriveSpeculativeName(typeIri: string): string | null {
  const match = typeIri.match(/([^/#]+)$/);
  return match?.[1] ?? null;
}

function resolveSubject(
  declaration: StructuredDataDeclaration,
  routeContext: StructuredDataRouteContext,
  context: StructuredDataContextMap
): StructuredDataNodeRef {
  if (declaration.sdId) {
    const iri = expandIri(declaration.sdId, context, routeContext.baseIri);
    if (iri.startsWith('_:')) {
      return { kind: 'blank', id: iri.slice(2) };
    }
    return { kind: 'iri', iri };
  }

  if (declaration.sdRef) {
    const iri = expandIri(declaration.sdRef, context, routeContext.baseIri);
    if (iri.startsWith('_:')) {
      return { kind: 'blank', id: iri.slice(2) };
    }
    return { kind: 'iri', iri };
  }

  const route = routeContext.routeId ?? '/';
  const line = declaration.sourceSpan?.startLine ?? 0;
  const column = declaration.sourceSpan?.startColumn ?? 0;
  return { kind: 'blank', id: `route-${normalizeNodeId(route)}-${line}-${column}` };
}

function sourceIndexToSpan(
  source: string,
  index: number,
  file: string
): StructuredDataSourceSpan {
  const before = source.slice(0, index);
  const line = before.split('\n').length;
  const lastNewline = before.lastIndexOf('\n');
  const col = index - (lastNewline + 1) + 1;
  return {
    file,
    startLine: line,
    startColumn: col,
    endLine: line,
    endColumn: col + 1,
  };
}

function parseAttributes(tag: string): Record<string, string> {
  const attrs: Record<string, string> = {};
  const attrRegex =
    /\b([A-Za-z_:][A-Za-z0-9_:.-]*)\s*=\s*(?:"([^"]*)"|'([^']*)'|\{\s*"([^"]*)"\s*\}|\{\s*'([^']*)'\s*\})/g;

  for (const match of tag.matchAll(attrRegex)) {
    const key = match[1];
    if (key === undefined) continue;
    const value =
      match[2] ?? match[3] ?? match[4] ?? match[5] ?? '';
    attrs[key] = value;
  }

  return attrs;
}

function parseContextMap(
  raw: string
): { context: StructuredDataContextMap } | { error: string } {
  try {
    const parsed = JSON.parse(raw) as unknown;
    if (!parsed || typeof parsed !== 'object' || Array.isArray(parsed)) {
      return { error: 'context must be a JSON object' };
    }
    const context: StructuredDataContextMap = {};
    for (const [key, value] of Object.entries(parsed as Record<string, unknown>)) {
      if (typeof value !== 'string') {
        return { error: `context prefix '${key}' must map to a string IRI` };
      }
      context[key] = value;
    }
    return { context };
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    return { error: message };
  }
}

function normalizeNodeId(value: string): string {
  return value.replace(/[^a-zA-Z0-9_]/g, '_');
}

function nodeKey(node: StructuredDataNodeRef): string {
  return node.kind === 'iri' ? node.iri : `_:${node.id}`;
}

function serializeNodeRef(node: StructuredDataNodeRef): string {
  return node.kind === 'iri' ? node.iri : `_:${node.id}`;
}

function expandIri(
  raw: string,
  context: StructuredDataContextMap,
  baseIri?: string
): string {
  const value = raw.trim();
  if (value.length === 0) {
    return value;
  }

  if (value.startsWith('_:')) {
    return value;
  }

  if (/^[A-Za-z][A-Za-z0-9+.-]*:\/\//.test(value)) {
    return value;
  }

  if (value.startsWith('#')) {
    if (baseIri) {
      return `${baseIri.replace(/\/$/, '')}${value}`;
    }
    return `_:${value.slice(1)}`;
  }

  const colonIndex = value.indexOf(':');
  if (colonIndex > 0) {
    const prefix = value.slice(0, colonIndex);
    const suffix = value.slice(colonIndex + 1);
    const iriBase = context[prefix];
    if (iriBase) {
      return `${iriBase}${suffix}`;
    }
    if (/^[A-Za-z][A-Za-z0-9+.-]*$/.test(prefix)) {
      return value;
    }
  }

  if (context.schema) {
    return `${context.schema}${value}`;
  }

  return value;
}

function compareDeclarationOrder(
  a: StructuredDataDeclaration,
  b: StructuredDataDeclaration
): number {
  const fa = a.sourceSpan?.file ?? '';
  const fb = b.sourceSpan?.file ?? '';
  if (fa !== fb) {
    return fa.localeCompare(fb);
  }
  const la = a.sourceSpan?.startLine ?? 0;
  const lb = b.sourceSpan?.startLine ?? 0;
  if (la !== lb) {
    return la - lb;
  }
  const ca = a.sourceSpan?.startColumn ?? 0;
  const cb = b.sourceSpan?.startColumn ?? 0;
  return ca - cb;
}

function vocabularyOfIri(iri: string): string | null {
  const hash = iri.lastIndexOf('#');
  if (hash !== -1) {
    return iri.slice(0, hash + 1);
  }
  const slash = iri.lastIndexOf('/');
  if (slash !== -1) {
    return iri.slice(0, slash + 1);
  }
  return null;
}

function literalToJsonLd(
  literal: StructuredDataLiteral
): string | Record<string, string> {
  if (!literal.language) {
    return literal.value;
  }
  return {
    '@value': literal.value,
    '@language': literal.language,
  };
}

function pushJsonLdValue(
  node: Record<string, unknown>,
  key: string,
  value: unknown
): void {
  const current = node[key];
  if (current === undefined) {
    node[key] = value;
    return;
  }
  if (Array.isArray(current)) {
    current.push(value);
    return;
  }
  node[key] = [current, value];
}

function compactIri(iri: string, context: StructuredDataContextMap): string {
  for (const [prefix, value] of Object.entries(context)) {
    if (iri.startsWith(value)) {
      return `${prefix}:${iri.slice(value.length)}`;
    }
  }
  return iri;
}

function groupTriplesBySubject(
  triples: StructuredDataTriple[]
): Map<string, StructuredDataTriple[]> {
  const map = new Map<string, StructuredDataTriple[]>();
  for (const triple of triples) {
    const key = serializeNodeRef(triple.subject);
    const existing = map.get(key) ?? [];
    existing.push(triple);
    map.set(key, existing);
  }
  return map;
}

function toMicrodataType(iri: string): string | null {
  if (!iri.startsWith(SCHEMA_BASE)) {
    return null;
  }
  return iri;
}

function toMicrodataProp(iri: string): string | null {
  if (!iri.startsWith(SCHEMA_BASE)) {
    return null;
  }
  return iri.slice(SCHEMA_BASE.length);
}

function escapeAttr(value: string): string {
  return value
    .replace(/&/g, '&amp;')
    .replace(/"/g, '&quot;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');
}
